```markdown
## Quickstart Example

```typescript
import {
  Model,
  TextProperty,
  IntegerProperty,
  ModelReferenceProperty,
  PrimaryKeyUuidProperty,
  DatetimeProperty,
} from 'functional-models'

// AI: Always use types, NEVER interfaces
type Author = { id: string; name: string }
type Book = {
  id: string
  title: string
  year: number
  author: Author
  lastModified?: Date
}

const Authors = Model<Author>({
  pluralName: 'Authors',
  namespace: 'library',
  description: 'Authors in the library domain',
  properties: {
    id: PrimaryKeyUuidProperty({ description: 'Primary key (UUID)' }),
    name: TextProperty({ required: true, maxLength: 50, description: 'Author name' }),
  },
})

const Books = Model<Book>({
  pluralName: 'Books',
  namespace: 'library',
  description: 'Books in the library domain',
  properties: {
    id: PrimaryKeyUuidProperty({ description: 'Primary key (UUID)' }),
    title: TextProperty({ required: true, description: 'Book title' }),
    year: IntegerProperty({ minValue: 1900, maxValue: 2100, description: 'Publication year' }),
    author: ModelReferenceProperty<Author>(Authors, { required: true, description: 'Author reference' }),
    lastModified: DatetimeProperty({ autoNow: true, description: 'Last modified timestamp' }),
  },
})

// AI: We have to add the id here (or others), so typescript doesnt complain that we are not including the auto-generated field
const rowling = Authors.create<'id'>({ name: 'J.K. Rowling' })
const hp = Books.create<'id'>({ title: 'HP1', year: 1997, author: rowling })
const errors = await hp.validate() // undefined if valid
const obj = await hp.toObj<Book>() // serializes for storage/transport, type-safe
```

**AI: Always await async property getters and .validate()/.toObj(). Prefer specifying the type parameter for .toObj().**
